('verbal', 'inference', '{3-5}', 0.5, 1.4, 0.20, '{"stem": "Maria put on her raincoat and grabbed her umbrella. What can you infer about the weather?", "type": "inference", "options": [{"text": "It is sunny"}, {"text": "It is raining or about to rain"}, {"text": "It is snowing"}, {"text": "It is windy"}], "correct_index": 1}'),
('verbal', 'vocabulary', '{3-5}', 0.5, 1.3, 0.20, '{"stem": "What does \"reluctant\" mean?", "type": "definition", "options": [{"text": "Eager"}, {"text": "Unwilling"}, {"text": "Confused"}, {"text": "Excited"}], "correct_index": 1}'),
('verbal', 'inference', '{3-5}', 1.0, 1.5, 0.20, '{"stem": "The dog wagged its tail and brought its leash to the door. What does the dog want?", "type": "inference", "options": [{"text": "Food"}, {"text": "A walk"}, {"text": "Sleep"}, {"text": "A bath"}], "correct_index": 1}'),
('verbal', 'reading_comprehension', '{3-5}', 1.0, 1.5, 0.20, '{"stem": "The library was quiet. Everyone whispered. Books lined every wall. Where is this?", "type": "comprehension", "options": [{"text": "A school gym"}, {"text": "A library"}, {"text": "A park"}, {"text": "A store"}], "correct_index": 1}'),
('verbal', 'vocabulary', '{3-5}', 1.5, 1.7, 0.15, '{"stem": "What does \"ubiquitous\" mean?", "type": "definition", "options": [{"text": "Very rare"}, {"text": "Found everywhere"}, {"text": "Very beautiful"}, {"text": "Hard to understand"}], "correct_index": 1}'),
('verbal', 'inference', '{3-5}', 1.5, 1.6, 0.15, '{"stem": "After the earthquake, the family slept outside in a tent. Why?", "type": "inference", "options": [{"text": "They like camping"}, {"text": "Their house may be unsafe"}, {"text": "It was summer"}, {"text": "The tent was new"}], "correct_index": 1}'),
('verbal', 'reading_comprehension', '{3-5}', 2.0, 1.8, 0.15, '{"stem": "The scientist carefully recorded each measurement twice. What does this tell you about the scientist?", "type": "comprehension", "options": [{"text": "She is bored"}, {"text": "She is thorough and careful"}, {"text": "She is slow"}, {"text": "She forgot the first time"}], "correct_index": 1}');
